judgeConfig.referenceSolution:
.card-container {
  perspective: 1000px;
}
.card-inner {
  transition: transform 0.6s;
  transform-style: preserve-3d;
}
.card-container:hover .card-inner {
  transform: rotateY(180deg);
}
.card-face {
  position: absolute;
  width: 100%; height: 100%;
  backface-visibility: hidden;
}
.card-back {
  transform: rotateY(180deg);
}
